@import url('https://fonts.googleapis.com/css2?family=Orbitron:wght@400;700;900&family=Space+Grotesk:wght@300;400;500;600&display=swap');

:root {
  --void: #02020c;
  --indigo: #6366f1;
  --violet: #8b5cf6;
  --lavender: #c4b5fd;
  --gold: #e4b84a;
  --white: #f1f5f9;
  --dim: rgba(241, 245, 249, 0.45);
  --dimmer: rgba(241, 245, 249, 0.18);
  --glass-bg: rgba(8, 8, 28, 0.72);
  --glass-border: rgba(139, 92, 246, 0.18);
  --space-1: 0.25rem;
  --space-2: 0.5rem;
  --space-3: 0.75rem;
  --space-4: 1rem;
  --space-5: 1.5rem;
  --space-6: 2rem;
  --space-7: 3rem;
  --space-8: 4rem;
  --ease-snappy: cubic-bezier(0.16, 1, 0.3, 1);
  --ease-smooth: cubic-bezier(0.4, 0, 0.2, 1);
}

*:focus-visible {
  outline: 2px solid rgba(139, 92, 246, 0.6);
  outline-offset: 3px;
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

html, body {
  height: 100%;
  overflow: hidden;
  background: var(--void);
  color: var(--white);
  font-family: 'Space Grotesk', system-ui, sans-serif;
  -webkit-font-smoothing: antialiased;
  overscroll-behavior: none;
}

/* Scrollbar */
::-webkit-scrollbar { width: 3px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: rgba(139, 92, 246, 0.3); border-radius: 2px; }

/* ── Keyframes ───────────────────────────────────────────────────── */

@keyframes omega-breathe {
  0%, 100% { filter: drop-shadow(0 0 18px rgba(99,102,241,0.6)) drop-shadow(0 0 50px rgba(139,92,246,0.25)); }
  50%       { filter: drop-shadow(0 0 30px rgba(139,92,246,0.9)) drop-shadow(0 0 80px rgba(99,102,241,0.35)); }
}

@keyframes omega-think {
  0%   { filter: drop-shadow(0 0 20px rgba(228,184,74,0.5)) drop-shadow(0 0 60px rgba(228,184,74,0.2)); transform: scale(1) rotate(0deg); }
  25%  { filter: drop-shadow(0 0 40px rgba(228,184,74,0.9)) drop-shadow(0 0 100px rgba(228,184,74,0.4)); transform: scale(1.04) rotate(1deg); }
  75%  { filter: drop-shadow(0 0 40px rgba(228,184,74,0.9)) drop-shadow(0 0 100px rgba(228,184,74,0.4)); transform: scale(1.04) rotate(-1deg); }
  100% { filter: drop-shadow(0 0 20px rgba(228,184,74,0.5)) drop-shadow(0 0 60px rgba(228,184,74,0.2)); transform: scale(1) rotate(0deg); }
}

@keyframes omega-respond {
  0%   { filter: drop-shadow(0 0 30px rgba(196,181,253,0.8)) drop-shadow(0 0 80px rgba(196,181,253,0.4)); }
  100% { filter: drop-shadow(0 0 18px rgba(99,102,241,0.6)) drop-shadow(0 0 50px rgba(139,92,246,0.25)); }
}

@keyframes fade-up {
  from { opacity: 0; transform: translateY(12px); }
  to   { opacity: 1; transform: translateY(0); }
}

@keyframes cursor-blink {
  0%, 100% { opacity: 1; }
  50%       { opacity: 0; }
}

@keyframes shimmer {
  0%   { background-position: -200% center; }
  100% { background-position:  200% center; }
}

@keyframes ring-pulse {
  0%   { transform: scale(1); opacity: 0.6; }
  100% { transform: scale(2.2); opacity: 0; }
}

@keyframes dot-bounce {
  0%, 80%, 100% { transform: translateY(0); opacity: 0.3; }
  40%            { transform: translateY(-6px); opacity: 1; }
}

/* ── Reduced motion ─────────────────────────────────────────────── */
@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    opacity: 1 !important;
  }
}

